.tag-chip-container {
  /* All CSS custom properties should be defined within the component */
  /* Color Palette based on original inspiration */
  --clr-primary-dark: #066e29;         /* From original title */
  --clr-accent-bright: #0afa2a;        /* From original SVG icon */
  --clr-light-bg: #e2feee;             /* From original image background */
  --clr-text-main: #242525;            /* From original track button text */
  --clr-text-subtle: #595b5f;          /* From original message text */
  --clr-white: #ffffff;
  --clr-border-light: #D1D5DB;         /* From original dismiss border */
  --clr-danger-red: #ee0d0d;           /* From original dismiss hover */

  /* Component specific variables */
  --tag-bg-start: var(--clr-white);
  --tag-bg-end: #f8f8f8; /* Slightly off-white for subtle gradient */
  --tag-border-color: var(--clr-border-light);
  --tag-text-color: var(--clr-text-main);
  --tag-accent-color: var(--clr-primary-dark);
  --tag-icon-color-default: var(--clr-text-subtle);
  --tag-padding-y: 0.4rem;
  --tag-padding-x: 0.9rem;
  --tag-font-size: 0.875rem; /* From original message */
  --tag-font-weight: 500; /* From original buttons */
  --tag-line-height: 1.25rem;
  --tag-gap: 0.4rem; /* Gap between label and icon/button */

  /* Shadows - mimicking original multi-layer approach */
  --shadow-base: 0 1px 2px 0 rgba(0, 0, 0, 0.05); /* Similar to original button shadow */
  --shadow-hover-blur-lg: 15px;
  --shadow-hover-offset-y-lg: 10px;
  --shadow-hover-color-lg: rgba(0, 0, 0, 0.08); /* Darker for hover */
  --shadow-hover-blur-md: 6px;
  --shadow-hover-offset-y-md: 4px;
  --shadow-hover-color-md: rgba(0, 0, 0, 0.04); /* Lighter for hover */

  /* Transitions */
  --transition-speed: 0.3s;
  --transition-ease: ease;

  display: flex; /* For displaying multiple chips */
  flex-wrap: wrap;
  gap: 1rem;
  padding: 1.5rem;
  background-color: #fcfcfc; /* A neutral background for the container */
  border-radius: 0.75rem;
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.08), 0 4px 6px -2px rgba(0, 0, 0, 0.04); /* Container shadow */
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; /* General font for consistency */
}

.tag-chip {
  display: inline-flex;
  align-items: center;
  gap: var(--tag-gap);
  padding: var(--tag-padding-y) var(--tag-padding-x);
  border-radius: 9999px; /* Pill shape */
  background: linear-gradient(145deg, var(--tag-bg-start), var(--tag-bg-end));
  border: 1px solid var(--tag-border-color);
  box-shadow: var(--shadow-base);
  color: var(--tag-text-color);
  font-size: var(--tag-font-size);
  line-height: var(--tag-line-height);
  font-weight: var(--tag-font-weight);
  cursor: default; /* Default cursor for general chip */
  transition: all var(--transition-speed) var(--transition-ease);
  text-decoration: none; /* In case it's an anchor */
  user-select: none;
}

/* Interactive Chip Hover State */
.tag-chip.is-interactive {
  cursor: pointer;
}
.tag-chip.is-interactive:hover {
  background: linear-gradient(145deg, #f0f0f0, #e8e8e8); /* Slightly darker gradient on hover */
  border-color: #c0c0c0; /* Darker border */
  box-shadow: var(--shadow-hover-offset-y-lg) var(--shadow-hover-blur-lg) var(--shadow-hover-color-lg),
              var(--shadow-hover-offset-y-md) var(--shadow-hover-blur-md) var(--shadow-hover-color-md);
  transform: translateY(-2px) scale(1.02); /* Lift and subtle scale */
}

.tag-chip__label {
  color: var(--tag-accent-color); /* Use primary dark green for label, like original title */
  white-space: nowrap; /* Prevent label from wrapping */
}

/* Action button (e.g., dismiss) within the chip */
.tag-chip__action-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 1.25rem; /* Smaller than original dismiss */
  height: 1.25rem;
  border-radius: 50%;
  background-color: transparent;
  border: none;
  padding: 0;
  cursor: pointer;
  transition: background-color var(--transition-speed) var(--transition-ease), transform 0.2s ease;
  flex-shrink: 0; /* Prevent button from shrinking */
}

.tag-chip__action-btn:hover {
  background-color: var(--clr-danger-red);
  transform: scale(1.1); /* Subtle scale on hover */
}

/* Icons within the chip */
.tag-chip__icon {
  width: 100%;
  height: 100%;
  color: var(--tag-icon-color-default); /* Default icon color */
  stroke-width: 2.5; /* Slightly thicker stroke for clarity */
  transition: color var(--transition-speed) var(--transition-ease);
}

/* Change icon color on button hover */
.tag-chip__action-btn:hover .tag-chip__icon {
  color: var(--clr-white);
}

/* Leading icon specific styles for the static chip */
.tag-chip__icon--leading {
  width: 1rem;
  height: 1rem;
  color: var(--clr-accent-bright); /* Bright green for leading icon, like original SVG */
  flex-shrink: 0;
}
